<script setup lang="ts">
import { reactive, watch } from 'vue'

import type { AvatarKey, User } from '@/types'

const props = withDefaults(defineProps<{ open: boolean; user: User; busy?: boolean; error?: string }>(), { busy:false,error:'' })
const emit = defineEmits<{ close: []; save: [payload:{ display_name:string; avatar_key:AvatarKey }] }>()
const avatars: Array<{ key:AvatarKey; label:string }> = [
  {key:'aurora',label:'极光'},{key:'coral',label:'珊瑚'},{key:'nebula',label:'星云'},{key:'ocean',label:'海洋'},
  {key:'sunset',label:'日落'},{key:'mint',label:'薄荷'},{key:'cosmos',label:'宇宙'},{key:'ember',label:'余烬'},
]
const form = reactive<{ displayName:string; avatarKey:AvatarKey }>({ displayName:props.user.display_name,avatarKey:props.user.avatar_key })
const errors = reactive({ displayName:'' })
watch(()=>props.open,(open)=>{if(open){form.displayName=props.user.display_name;form.avatarKey=props.user.avatar_key;errors.displayName=''}})
function submit():void{const name=form.displayName.trim();errors.displayName=!name||name.length>40?'显示名称必须为 1–40 个字符':'';if(!errors.displayName)emit('save',{display_name:name,avatar_key:form.avatarKey})}
</script>

<template><Transition name="drawer"><div v-if="open" class="drawer-layer" role="presentation" @click.self="emit('close')"><aside class="identity-drawer" aria-label="编辑数字身份"><header><div><span>DIGITAL IDENTITY</span><h2>编辑数字身份</h2></div><button type="button" aria-label="关闭" @click="emit('close')">×</button></header><div class="identity-preview"><i :data-avatar="form.avatarKey">{{ form.displayName.trim().slice(0,1).toUpperCase()||'✦' }}</i><div><b>{{ form.displayName.trim()||user.username }}</b><span>@{{ user.username }} · {{ user.role }}</span></div></div><form @submit.prevent="submit"><label><span>显示名称</span><input v-model="form.displayName" name="display-name" maxlength="40"/><small :class="{error:errors.displayName}">{{ errors.displayName||'用户名不可修改，显示名称可随时更新' }}</small></label><fieldset><legend>选择主题头像</legend><div class="avatar-options"><button v-for="avatar in avatars" :key="avatar.key" type="button" :data-avatar="avatar.key" :class="{selected:form.avatarKey===avatar.key}" @click="form.avatarKey=avatar.key"><i>{{ form.displayName.trim().slice(0,1).toUpperCase()||'✦' }}</i><span>{{ avatar.label }}</span></button></div></fieldset><p v-if="error" class="api-error">{{ error }}</p><el-button type="primary" native-type="submit" :loading="busy">保存数字身份</el-button></form></aside></div></Transition></template>

<style scoped>.drawer-layer{background:rgba(22,15,39,.4);inset:0;position:fixed;z-index:200;backdrop-filter:blur(8px)}.identity-drawer{background:radial-gradient(circle at 100% 0,#e7dcff,transparent 28%),#faf9fe;box-shadow:-25px 0 75px rgba(28,18,52,.24);height:100%;margin-left:auto;overflow:auto;padding:27px;width:min(470px,94vw)}.identity-drawer header{align-items:start;display:flex;justify-content:space-between}.identity-drawer header span{color:#7657df;font-family:var(--font-mono);font-size:9px;letter-spacing:.16em}.identity-drawer h2{font-size:27px;margin:5px 0 22px}.identity-drawer header button{background:#eee8f8;border:0;border-radius:50%;color:#6d5b81;cursor:pointer;font-size:22px;height:36px;width:36px}.identity-preview{align-items:center;background:linear-gradient(145deg,#1d1535,#392366);border-radius:20px;color:white;display:flex;gap:15px;margin-bottom:24px;padding:18px}.identity-preview>i,.avatar-options i{background:linear-gradient(135deg,#ff6900,#ce5cdd);border-radius:14px;display:grid;font-style:normal;height:52px;place-items:center;width:52px}.identity-preview b,.identity-preview span{display:block}.identity-preview span{font-size:10px;margin-top:5px;opacity:.6}.identity-drawer form{display:grid;gap:22px}.identity-drawer label{display:grid;gap:7px}.identity-drawer label>span,.identity-drawer legend{color:#463952;font-size:12px;font-weight:650}.identity-drawer input{border:1px solid #ddd5eb;border-radius:12px;font:inherit;height:44px;padding:0 12px}.identity-drawer small{color:#91879c;font-size:10px}.identity-drawer .error,.api-error{color:#c83d5a}.identity-drawer fieldset{border:0;margin:0;padding:0}.avatar-options{display:grid;gap:8px;grid-template-columns:repeat(4,1fr);margin-top:11px}.avatar-options button{background:white;border:1px solid #e4ddef;border-radius:14px;cursor:pointer;padding:8px}.avatar-options button.selected{border-color:#7657df;box-shadow:0 0 0 3px #7657df18}.avatar-options i{height:42px;margin:auto;width:42px}.avatar-options button[data-avatar='ocean'] i{background:linear-gradient(135deg,#128ddd,#51d0c4)}.avatar-options button[data-avatar='mint'] i{background:linear-gradient(135deg,#0ca98a,#a4df86)}.avatar-options button[data-avatar='sunset'] i{background:linear-gradient(135deg,#ff5d6c,#ffb45d)}.avatar-options button[data-avatar='cosmos'] i{background:linear-gradient(135deg,#6547d8,#d45ac7)}.avatar-options button[data-avatar='ember'] i{background:linear-gradient(135deg,#c83c28,#ff8a38)}.avatar-options span{color:#7c7188;display:block;font-size:9px;margin-top:5px}.identity-drawer .el-button{height:45px;width:100%}.drawer-enter-active,.drawer-leave-active{transition:opacity .25s}.drawer-enter-active .identity-drawer,.drawer-leave-active .identity-drawer{transition:transform .25s}.drawer-enter-from,.drawer-leave-to{opacity:0}.drawer-enter-from .identity-drawer,.drawer-leave-to .identity-drawer{transform:translateX(100%)}@media(prefers-reduced-motion:reduce){.drawer-enter-active,.drawer-leave-active,.drawer-enter-active .identity-drawer,.drawer-leave-active .identity-drawer{transition:none}}</style>
